import pytest
import requests

BASE = "http://localhost:8080/fhir"

@pytest.fixture
def clinician_headers():
    return <fixture_clinician_auth_headers>

@pytest.fixture
def two_observation_ids(clinician_headers):
    return <fixture_create_two_observations>(clinician_headers)

def test_diagnostic_report_with_valid_observations_returns_201(
    clinician_headers, two_observation_ids
):
    obs_refs = [
        {"reference": f"Observation/{two_observation_ids[0]}"},
        {"reference": f"Observation/{two_observation_ids[1]}"}
    ]
    payload = {
        "resourceType": "DiagnosticReport",
        "status": "final",
        "code": {"text": "Lab Panel"},
        "result": obs_refs
    }
    resp = requests.post(
        f"{BASE}/DiagnosticReport",
        json=payload,
        headers=clinician_headers
    )
    assert resp.status_code == 201
    body = resp.json()
    assert body.get("resourceType") == "DiagnosticReport"
    assert body.get("id")
    assert "Location" in resp.headers

import pytest
import requests

BASE = "http://localhost:8080/fhir"

@pytest.fixture
def clinician_headers():
    return <fixture_clinician_auth_headers>

@pytest.fixture
def one_observation_id(clinician_headers):
    return <fixture_create_one_observation>(clinician_headers)

def test_diagnostic_report_with_exactly_one_observation_is_accepted(
    clinician_headers, one_observation_id
):
    payload = {
        "resourceType": "DiagnosticReport",
        "status": "final",
        "code": {"text": "Single Obs Panel"},
        "result": [{"reference": f"Observation/{one_observation_id}"}]
    }
    resp = requests.post(
        f"{BASE}/DiagnosticReport",
        json=payload,
        headers=clinician_headers
    )
    assert resp.status_code == 201
    body = resp.json()
    assert body.get("resourceType") == "DiagnosticReport"
    result = body.get("result", [])
    assert len(result) == 1
    assert one_observation_id in result[0].get("reference", "")
